-- ************************************** ANALYTICS.VW_CLAIM_ANALYSIS
CREATE VIEW ANALYTICS.VW_CLAIM_ANALYSIS
(
  CREATED_TIMESTAMP,
  CREATED_BY_NAME,
  UPDATED_TIMESTAMP,
  UPDATED_BY_NAME
)
AS
SELECT 
    c.CLAIM_KEY,
    c.CLAIM_ID,
    p.PATIENT_KEY,
    p.PATIENT_ID,
    p.FIRST_NAME || ' ' || p.LAST_NAME AS PATIENT_NAME,
    pp.PAYER_PLAN_KEY,
    pp.PAYER_PLAN_ID,
    pp.PAYER_NAME,
    pp.PLAN_NAME,
    dd_submit.CALENDAR_DATE AS CLAIM_SUBMIT_DATE,
    dd_paid.CALENDAR_DATE AS CLAIM_PAID_DATE,
    c.CLAIM_STATUS,
    c.CLAIM_TYPE,
    c.TOTAL_BILLED_AMOUNT,
    c.TOTAL_ALLOWED_AMOUNT,
    c.TOTAL_PAID_AMOUNT,
    c.TOTAL_DENIED_AMOUNT,
    (c.TOTAL_BILLED_AMOUNT - c.TOTAL_ALLOWED_AMOUNT) AS CONTRACTUAL_ADJUSTMENT,
    (c.TOTAL_ALLOWED_AMOUNT - c.TOTAL_PAID_AMOUNT) AS PATIENT_RESPONSIBILITY,
    COUNT(DISTINCT ccl.CLAIM_LINE_KEY) AS LINE_ITEM_COUNT,
    SUM(ccl.LINE_BILLED_AMOUNT) AS SUM_LINE_BILLED,
    SUM(ccl.LINE_ALLOWED_AMOUNT) AS SUM_LINE_ALLOWED,
    SUM(ccl.LINE_PAID_AMOUNT) AS SUM_LINE_PAID
FROM ANALYTICS.FACT_CLAIM c
LEFT JOIN ANALYTICS.DIM_PATIENT p ON c.PATIENT_KEY = p.PATIENT_KEY AND p.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_PAYER_PLAN pp ON c.PAYER_PLAN_KEY = pp.PAYER_PLAN_KEY AND pp.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_DATE dd_submit ON c.CLAIM_SUBMIT_DATE_KEY = dd_submit.DATE_KEY
LEFT JOIN ANALYTICS.DIM_DATE dd_paid ON c.CLAIM_PAID_DATE_KEY = dd_paid.DATE_KEY
LEFT JOIN ANALYTICS.FACT_CLAIM_LINE ccl ON c.CLAIM_KEY = ccl.CLAIM_KEY
GROUP BY 
    c.CLAIM_KEY,
    c.CLAIM_ID,
    p.PATIENT_KEY,
    p.PATIENT_ID,
    p.FIRST_NAME,
    p.LAST_NAME,
    pp.PAYER_PLAN_KEY,
    pp.PAYER_PLAN_ID,
    pp.PAYER_NAME,
    pp.PLAN_NAME,
    dd_submit.CALENDAR_DATE,
    dd_paid.CALENDAR_DATE,
    c.CLAIM_STATUS,
    c.CLAIM_TYPE,
    c.TOTAL_BILLED_AMOUNT,
    c.TOTAL_ALLOWED_AMOUNT,
    c.TOTAL_PAID_AMOUNT,
    c.TOTAL_DENIED_AMOUNT;

